def replace_max_specialchar(s, n):
    result = []
    count = 0
    for char in s:
        if char in [' ', ',', '.']:
            if count < n:
                result.append(':')
                count += 1
            else:
                result.append(char)
        else:
            result.append(char)
    return ''.join(result)

